#[test]
fn test_error_extract_bytes_conflicting_ocr() {
    // extract_bytes force+disable OCR
    let data = std::fs::read(concat!(env!("CARGO_MANIFEST_DIR"), "/../test_documents/SGVsbG8="))
        .expect("test_documents/SGVsbG8= must exist");
    let mime_type = r#"text/plain"#;
    let config_json = serde_json::json!({"disable_ocr": true, "force_ocr": true});
    let config = serde_json::from_value(config_json).unwrap();
    let result = extract_bytes_sync(&data, mime_type, &config);
    assert!(result.is_err(), "expected call to fail");
}

